   199→            }
   200→
   201→            if (key === "tags" && Array.isArray(val)) {
   202→              return (
   203→                <div key={key} className="prop-field">
   204→                  <EditableValue
   205→                    fieldKey={key}
   206→                    value={val}
   207→                    onSave={(v) => onFieldChange?.(key, v)}
