   229→                  <EditableValue
   230→                    fieldKey={key}
   231→                    value={val}
   232→                    onSave={(v) => onFieldChange?.(key, v)}
   233→                  />
   234→                </div>
   235→              );
   236→            }
   237→
   238→            return (
   239→              <div key={key} className="prop-field">
   240→                <span className="prop-label">{key}</span>
   241→                <EditableValue fieldKey={key} value={val} onSave={(v) => onFieldChange?.(key, v)} />
   242→              </div>
   243→            );
   244→          })}
   245→        </div>
   246→      </div>
   247→      <button
   248→        type="button"
   249→        className="properties-toggle"
   250→        onClick={onToggle}
   251→        title={isOpen ? "Hide properties" : "Show properties"}
   252→        aria-label="Toggle properties panel"
   253→      >
   254→        {isOpen ? "›" : "‹"}
   255→      </button>
   256→    </div>
   257→  );
   258→}
