   192→#[tauri::command]
   193→async fn open_workspace_at_path(
   194→    path: String,
   195→    state: State<'_, WorkspaceState>,
   196→) -> Result<Option<WorkspaceResult>, String> {
   197→    let root = PathBuf::from(&path);
   198→    if !root.is_dir() {
   199→        return Ok(None);
   200→    }
   201→
   202→    let name = root
   203→        .file_name()
   204→        .map(|n| n.to_string_lossy().to_string())
   205→        .unwrap_or_else(|| root.to_string_lossy().to_string());
   206→
   207→    let content_dir = root.join("content");
   208→    let tree_root = if content_dir.is_dir() { content_dir } else { root.clone() };
   209→
   210→    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
   211→    *state.workspace_root.lock().map_err(|e| e.to_string())? = Some(root.clone());
   212→
   213→    let is_amytis_workspace = root.join("site.config.ts").is_file() && root.join("content").is_dir();
   214→    let tree = walk_dir(&tree_root);
   215→
   216→    Ok(Some(WorkspaceResult {
   217→        name,
   218→        root_path: root.to_string_lossy().to_string(),
   219→        tree_root: tree_root.to_string_lossy().to_string(),
   220→        tree,
   221→        is_amytis_workspace,
   222→    }))
   223→}
