   613→/// Compute a POSIX-style relative path from `from_dir` to `to`.
   614→fn relative_path_from(from_dir: &Path, to: &Path) -> String {
   615→    let from: Vec<_> = from_dir.components().collect();
   616→    let to_c: Vec<_> = to.components().collect();
   617→    let common = from.iter().zip(to_c.iter()).take_while(|(a, b)| a == b).count();
   618→    let mut rel = PathBuf::new();
   619→    for _ in common..from.len() {
   620→        rel.push("..");
   621→    }
   622→    for c in &to_c[common..] {
   623→        rel.push(c);
   624→    }
   625→    rel.to_string_lossy().replace('\\', "/")
   626→}
